SELECT player_name, total_winnings, total_buy_ins, total_tournaments
FROM players
WHERE total_tournaments = (
    SELECT MAX(total_tournaments) FROM players
);

SELECT COUNT(*) 
FROM player_tournament_records 
WHERE player_id = 0;

SELECT player_id, COUNT(DISTINCT tournament_id) AS num_tournaments
FROM player_tournament_records
GROUP BY player_id;

SELECT player_name, total_winnings, total_buy_ins
FROM players
WHERE rating >= 5 AND total_tournaments >= (SELECT COUNT(tournament_id) / 2 FROM tournaments);

SELECT DISTINCT p.player_id, p.player_name
FROM players p
JOIN player_tournament_records ptr ON p.player_id = ptr.player_id;

SELECT COUNT(DISTINCT ptr.tournament_id) AS Tournament_count
FROM player_tournament_records ptr
JOIN seating s ON ptr.player_id = s.player_id
WHERE ptr.winnings > (s.chips / 2) AND ptr.tournament_id IN (
    SELECT tournament_id FROM tournaments
);

SELECT COUNT(*)
FROM seating
WHERE table_id = 0 AND seat_number > 5;
